sql:
SELECT diagnosis
FROM patient_history
WHERE history_status = 'active';

SELECT patient_id
FROM patient_medications
WHERE medication_status = 'active';

SELECT medication_name, COUNT(*) AS total_count
FROM patient_medications
GROUP BY medication_name;

SELECT patient_id, COUNT(allergy_id) AS allergy_count
FROM patient_allergies
GROUP BY patient_id;

SELECT facility_name
FROM facilities
WHERE facility_id = (SELECT facility_id FROM test_results WHERE result_id = 1);

SELECT comment_text
FROM test_comments
WHERE comment_status = 'active';

SELECT COUNT(comment_id) AS active_comments_count
FROM test_comments
WHERE test_id = 0 AND comment_status = 'active';
